-- W2 catalog seed batch3_fruit_vines_succulents — 15 cited profiles (generated from PlantAppPlanner scratch/catalog/profiles; sources embedded per row).
-- Upsert: already-seeded Slice-1 ids are enriched in place (version bump), never duplicated.
insert into public.plant_profiles (
  id, scientific_name, common_names, category, growth_habit, requires_support, self_fruitful, pollination_partners_required, watering_profile, feeding_profile, container_profile, light_profile, temperature_profile, seasonality, common_issues, vertical_suitability, source, version, last_reviewed_at
) values
  ('actinidia-deliciosa', 'Actinidia deliciosa', array['Kiwi','Kiwifruit','Fuzzy kiwifruit','Chinese gooseberry']::text[], 'vine', 'climbing', true, false, 1, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"preferredNpk":"balanced N-rich (apply ~50-60% of annual nitrogen in Mar-Apr, balance May-Jul)"}'::jsonb, '{"recommendedMinLiters":76,"idealMinLiters":95,"soilMixTags":["well-drained","sandy-loam","potting-mix-with-compost","slightly-acidic"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6}'::jsonb, '{"coldHardyMinC":-12,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[10,11],"dormancyMonths":[12,1,2]}'::jsonb, array['Dioecious: a separate male vine is required to pollinate female vines for fruit; one male can pollinate several females. Vines cannot be sexed until they bloom.','Spring shoots are very frost tender; spring frost below about -1 C (30 F) damages new growth, and an early fall frost can damage unharvested fruit.','Requires 600-700 winter chilling hours below 7 C (45 F) and roughly 225-240 frost-free days to crop, so it fruits reliably only in USDA zones 7-9.','Vigorous, heavy vine that needs a permanent, strong trellis, T-bar, arbor, or pergola; never let it climb a tree or weak structure.','Container note: this is naturally a large in-ground vine (15-30 ft). The recommended minimum container is a conservative large pot (~76 L / 20 US gal); fruiting in a container is reduced versus in-ground and still demands a sturdy trellis.','High water demand; provide good drainage to avoid root rot, especially in containers where overwatering risk is higher.','Does not bear a first crop until roughly the 3rd-4th year after planting.']::text[], 0.95, '[{"citation":"Oregon State University Extension Service, EM 9322 ''Growing kiwifruit in your home garden'': cold hardy to about 0-10 F; 225-240 frost-free days; full sun preferred; fertile well-drained sandy/clay loam, pH 5.6-6.5; 0.5-1 lb N per vine/year (two-thirds in March, one-third May/June); permanent strong T-bar (6-7 ft) or arbor (7-8 ft) trellis required; one male per female; first crop in the third year.","url":"https://extension.oregonstate.edu/catalog/em-9322-growing-kiwifruit-your-home-garden","field":"temperatureProfile"},{"citation":"Oregon State University Extension Service, EM 9322: requires a permanent strong trellis (T-bar or arbor); one male vine pollinates female vines; vines are dioecious and only sexable at bloom.","url":"https://extension.oregonstate.edu/catalog/em-9322-growing-kiwifruit-your-home-garden","field":"requiresSupport"},{"citation":"Oregon State University Extension Service, EM 9322: fertilize with 0.5-1 lb nitrogen per vine per year, applying two-thirds in March and one-third in May/June.","url":"https://extension.oregonstate.edu/catalog/em-9322-growing-kiwifruit-your-home-garden","field":"feedingProfile"},{"citation":"North Carolina State Extension Gardener Plant Toolbox, Actinidia chinensis var. deliciosa: USDA zones 7a-9b; full sun (6+ hours direct sunlight a day) or dappled shade with reduced fruiting; needs good drainage / well-drained soil; deciduous twining/climbing woody vine 15-30 ft tall, 6-10 ft wide; sturdy trellis recommended; dioecious, needs both a male and a female to fruit; spring flowering, fruit ripens in early fall.","url":"https://plants.ces.ncsu.edu/plants/actinidia-chinensis-var-deliciosa/","field":"lightProfile"},{"citation":"North Carolina State Extension Gardener Plant Toolbox: deciduous twining climbing/spreading woody vine reaching 15-30 ft; a sturdy trellis is recommended; can be trained on an arbor, patio overhead, wall, or fence.","url":"https://plants.ces.ncsu.edu/plants/actinidia-chinensis-var-deliciosa/","field":"growthHabit"},{"citation":"UC ANR Small Farms Network, Kiwifruit Production in California: bearing plants irrigated three to four times per week (young vines daily or every two days for the first 3 years); requires 600-700 winter chilling hours below 45 F and 225-240 frost-free days; minimum safe winter temperature about 10-15 F; spring frost damage below 30 F; ~1 lb nitrogen per vine for full-bearing vines with 50-60% applied Mar-Apr and balance May-Jul; soil pH below 7.3; ~4 years to a commercial crop.","url":"https://ucanr.edu/statewide-program/uc-anr-small-farms-network/kiwifruit-production-california","field":"wateringProfile"},{"citation":"UC ANR Small Farms Network: full-bearing vines take about 1 lb nitrogen per plant; apply at least 50-60% in March-April and the balance in May, June and July; young vines scale by age. Used to set feeding interval and N timing.","url":"https://ucanr.edu/statewide-program/uc-anr-small-farms-network/kiwifruit-production-california","field":"feedingProfile"},{"citation":"UC ANR Small Farms Network: winter chilling requirement 600-700 hours below 45 F, minimum safe winter temperature about 10-15 F (~-12 to -9 C), spring frost damage below 30 F; basis for coldHardyMinC and frostSensitive.","url":"https://ucanr.edu/statewide-program/uc-anr-small-farms-network/kiwifruit-production-california","field":"temperatureProfile"},{"citation":"Confidence note: baseIntervalDays=2 is derived from extension guidance to irrigate bearing vines ''three to four times per week'' (OSU/UC ANR) and conservatively reflects this plant''s high water demand; exact day-interval is climate dependent. hotWeatherMultiplier (0.5) and rainSkipThresholdMm (12) are reasonable estimates not given as explicit numbers in the sources.","field":"confidence"},{"citation":"Confidence note: heatStressC=35 is an estimate. Reviewed extension pages emphasize cold/frost tolerance and chilling requirement but do not state an explicit upper heat-stress temperature for Actinidia deliciosa; 35 C is a conservative placeholder pending an authoritative figure.","field":"confidence"},{"citation":"Confidence note: recommendedMinLiters=76 (~20 US gal) and idealMinLiters=95 are converted from horticulture guidance that fuzzy kiwi needs a final container of at least 20 gallons (larger for vigorous fuzzy types). This is a container-adaptation estimate; A. deliciosa is naturally a large in-ground vine and the university extension sources treat it as ground/trellis grown rather than a container crop.","field":"containerProfile"}]'::jsonb, 1, '2026-06-02'),
  ('aloe-vera', 'Aloe vera', array['Aloe vera','Aloe','Barbados Aloe','Medicinal Aloe','True Aloe']::text[], 'succulent', 'rosette', false, null, 0, '{"baseIntervalDays":14,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.75,"rainSkipThresholdMm":3}'::jsonb, '{"baseIntervalDays":60,"preferredNpk":"higher-phosphorus houseplant fertilizer (e.g. 10-15-10) diluted to half strength, growing season only"}'::jsonb, '{"recommendedMinLiters":3,"idealMinLiters":4,"idealMaxLiters":10,"soilMixTags":["cactus-succulent-mix","sandy","sharp-drainage","unglazed-clay-pot","drainage-holes-required"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":4,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"productiveMonths":[3,4,5,6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot from overwatering or poor drainage — the number-one killer; let soil dry completely between waterings and use a pot with drainage holes','Reduce watering to a minimum in winter (dormant period); soil should be barely moist','Mealybugs, scale, and aphids','Sunburn when moved from low light to bright direct sun too quickly — transition gradually','Not frost tolerant; bring indoors before night temperatures dip below 10C (50F)','Outdoor summer plants should be protected from rain to avoid waterlogged soil','An oversized pot holds excess moisture and promotes root rot — pot up only 2.5-4 cm (1-1.5 in) wider than the root ball','Mildly toxic to cats, dogs, and horses if ingested','Indoor plants rarely flower; mature plants (3+ years) in bright light may bloom']::text[], 0.2, '[{"citation":"Missouri Botanical Garden Plant Finder — Aloe vera: water very moderately spring–fall, minimum watering in winter; full sun, adapts to part shade; winter minimum 40F (4C); bring indoors before nights drop below 50F; protect outdoor plants from rain; hardy zones 10-12; sandy well-drained potting loam","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b628","field":"wateringProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Aloe vera: winter minimum 40F (~4C); not frost hardy below zone 10; bring indoors before night temps dip below 50F","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=b628","field":"temperatureProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Aloe vera: full sun (6 or more hours of direct sunlight a day) to partial shade; allow soil to completely dry between waterings; water less in winter; very well-drained succulent soil; clay pot with several drainage holes; zones 10a-12b; rosette habit spreading by offsets; mealybugs, aphids, scale; toxic to cats/dogs/horses (low severity)","url":"https://plants.ces.ncsu.edu/plants/aloe-vera/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Aloe vera: allow soil to completely dry between waterings; overwatering causes root rot; clay pot with drainage holes recommended","url":"https://plants.ces.ncsu.edu/plants/aloe-vera/","field":"wateringProfile"},{"citation":"Penn State Extension, ''Aloe, a Hardy Houseplant'' — water thoroughly when soil surface is dry during growing season (spring–early fall); keep barely moist during fall–winter dormancy; err on the side of underwatering (root-rot prone); repot every ~2 years into a pot only 1-1.5 in larger than the root ball; coarse cactus/succulent mix; not frost tolerant","url":"https://extension.psu.edu/aloe-a-hardy-houseplant","field":"containerProfile"},{"citation":"UF/IFAS Gardening Solutions — Aloe Vera: water only when top inch of soil is dry, water well, never let plant sit in water; do not increase pot by more than two sizes (oversized pots hold excess moisture and cause root rot); zones 8-11 outdoors; sunburn when moved to bright light too quickly","url":"https://gardeningsolutions.ifas.ufl.edu/plants/ornamentals/aloe-vera/","field":"containerProfile"},{"citation":"University of Minnesota Extension, ''Cacti and succulents'' — allow soil to dry completely between waterings; water minimally in winter; fertilize succulents three to four times during the brighter months with a half-strength houseplant fertilizer higher in phosphorus than nitrogen; bright sunny window; pots must have drainage holes; one part potting soil to one part coarse sand","url":"https://extension.umn.edu/houseplants/cacti-and-succulents","field":"feedingProfile"},{"citation":"Confidence note: extension sources give moisture-based rules (''water when soil is completely dry''), not fixed day counts; baseIntervalDays=14 is a conservative planner estimate of that drying cycle for a typical indoor pot. feedingProfile.baseIntervalDays=60 is derived from UMN''s ''3-4 times during the brighter months''. heatStressC=38 and container liters (3-10 L ≈ 15-25 cm pots, per PSU/UF pot-sizing guidance for a 1-2 ft rosette) are reasoned conversions, not directly published figures.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('citrus-limon', 'Citrus limon', array['Lemon','Meyer Lemon']::text[], 'fruit', 'tree', false, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.4,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":30,"fruitingIntervalDays":21,"postHarvestIntervalDays":45,"containerLeachAdjustment":0.75,"preferredNpk":"12-6-6"}'::jsonb, '{"recommendedMinLiters":26,"idealMinLiters":45,"idealMaxLiters":90,"soilMixTags":["well-drained","citrus-mix","acidic","added-grit-or-sharp-sand"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":5,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"9":[{"startMonth":3,"endMonth":5}],"10":[{"startMonth":2,"endMonth":5}]},"productiveMonths":[11,12,1,2,3]}'::jsonb, array['Frost tender: leaves and fruit are damaged below about 0 C (32 F) and the tree suffers significant injury below roughly -4 C (25 F); in climates colder than USDA zone 8b/9a grow in a container and overwinter indoors, in a greenhouse, conservatory or glazed porch (RHS, NC State Extension).','Overwatering / waterlogging is a primary killer: lemons dislike soggy roots. Let the top 2-3 inches of soil dry, then water thoroughly; never let the root ball fully dry out or stay saturated (Clemson HGIC, UMD Extension).','Container note: a lemon is naturally a 6-10 ft tree. The recommended minimum here (~26 L, a 14 in pot) is a starting size for a small or dwarf tree; pot up gradually toward 45-90 L (18-24 in) as it grows. In-ground in zones 9-11 it needs far more root room than any container (Clemson HGIC, RHS).','Container plants leach nutrients quickly under frequent watering; use a slow-release citrus feed (e.g. 12-6-6 or 12-4-6) and feed only during active growth, stopping by early fall (UMD Extension, Clemson HGIC).','Needs high light: 6 hours minimum, 8-12 hours ideal. Insufficient light causes poor fruiting and leggy growth (UMD Extension, NC State Extension).']::text[], 0, '[{"citation":"RHS - How to grow citrus (growing guide). Lemons tolerate a winter minimum ''as low as 5C (42F)''; citrus ''won''t reliably survive winters outdoors'' in the UK and are grown in containers brought under cover; water regularly in summer (compost dries quickly), let surface partially dry in winter; feed with a summer citrus feed late March-October and a balanced winter feed November-mid March; add up to 20% sharp sand/grit for drainage.","url":"https://www.rhs.org.uk/plants/citrus/growing-guide","field":"temperatureProfile"},{"citation":"RHS - How to grow citrus. Feeding cadence (summer high-nitrogen citrus feed late March-October; balanced winter feed) and drainage/soil-mix guidance.","url":"https://www.rhs.org.uk/plants/citrus/growing-guide","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC - Container Citrus Production. Container diameter 18-36 inches at maturity, pot up ~2 inches wider each step; near-daily watering in hot dry periods, check top 2-3 inches, never fully dry or waterlogged; slow-release 12-6-6 or 12-4-6, 2-3 applications per growing season; optimum 65-85F, most species damaged below 25F.","url":"https://hgic.clemson.edu/factsheet/container-citrus-production/","field":"containerProfile"},{"citation":"Clemson Cooperative Extension HGIC - Container Citrus Production. Watering: near-daily in hot dry periods, irrigate when top 2-3 inches dry, never let root ball fully dry or stay saturated.","url":"https://hgic.clemson.edu/factsheet/container-citrus-production/","field":"wateringProfile"},{"citation":"University of Maryland Extension - Growing Dwarf Citrus. Light: at least 6 hours direct sun, optimal 8-12 hours; fertilize with 2-1-1 or 3-1-1 N-P-K at least three times per growing season (spring, early summer, late summer), only during active growth; daytime 65-75F / night 55-65F preferred; most citrus damaged below 32F; outdoor summer plants may need daily watering.","url":"https://extension.umd.edu/resource/growing-dwarf-citrus","field":"lightProfile"},{"citation":"University of Maryland Extension - Growing Dwarf Citrus. Feeding frequency (~3 times per growing season, active-growth only) and watering (daily in summer outdoors; indoors check top 2 inches once or twice weekly).","url":"https://extension.umd.edu/resource/growing-dwarf-citrus","field":"feedingProfile"},{"citation":"NC State Extension Gardener Plant Toolbox - Citrus x limon ''Meyer''. Full sun (6+ hours) preferred for fruit production; small broadleaf evergreen tree, erect habit, 6-10 ft tall x 4-8 ft wide; USDA zones 8b-11b; cannot survive frosts, grow in containers and bring indoors below zone 8b/9a; well-drained acid-to-neutral soil, prefers drying out then a good watering.","url":"https://plants.ces.ncsu.edu/plants/citrus-x-limon-meyer/","field":"growthHabit"},{"citation":"NC State Extension Gardener Plant Toolbox - Citrus x limon ''Meyer''. Frost/cold: ''cannot survive frosts'', container-overwinter below zone 8b/9a; light: full sun 6+ hours best.","url":"https://plants.ces.ncsu.edu/plants/citrus-x-limon-meyer/","field":"temperatureProfile"},{"citation":"Confidence note: heatStressC (38 C) is a conservative estimate. Clemson HGIC gives an optimum fruiting range of 65-85F (18-29 C) but does not state an explicit upper heat-stress threshold for lemon; 38 C is a conservative typical citrus heat-stress figure pending an explicit extension value. Watering baseIntervalDays (3) and hotWeatherMultiplier (0.4) are derived from qualitative ''near-daily in hot dry periods / let top 2-3 inches dry'' guidance rather than a published fixed interval. Container recommendedMinLiters (26 L) is converted from the 14-16 inch starter pot referenced for small/dwarf trees; idealMin/Max (45-90 L) map to the 18-24 inch / up-to-36 inch range. productiveMonths reflect the typical northern-hemisphere winter lemon harvest and is approximate.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('crassula-ovata', 'Crassula ovata', array['Jade plant','Jade tree','Money plant','Friendship plant']::text[], 'succulent', 'bush', false, null, 0, '{"baseIntervalDays":14,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.75}'::jsonb, '{"baseIntervalDays":60,"preferredNpk":"10-10-10 (balanced liquid houseplant fertilizer, diluted)"}'::jsonb, '{"recommendedMinLiters":2,"idealMinLiters":3,"idealMaxLiters":10,"soilMixTags":["cactus-mix","succulent-mix","well-draining","coarse-sand","perlite"]}'::jsonb, '{"targetSunHours":5,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":1,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[3,4,5,6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root and stem rot from overwatering or poorly drained soil — the most common killer; always let soil dry between waterings','Mealybugs (remove with rubbing-alcohol-soaked cotton swab); also watch for spider mites, scale, and aphids','Leaf drop, spotting, and dwarfing from extreme drought — despite being a succulent it still needs regular water in the growing season','Leggy, drooping, deep-green growth when light is insufficient (needs 4+ hours of direct sun)','Mature plants become top-heavy and tip over — use a heavy pot; insecticide sprays can scorch succulent leaves','Freezing temperatures kill the plant; bring indoors before first frost (tolerates only the lightest frost)']::text[], 0.1, '[{"citation":"Clemson Cooperative Extension HGIC, ''Jade Plant'' factsheet — needs four or more hours/day of direct sun (south window); keep soil moist in spring/summer, dry between waterings in winter; ideal 18-24 C day, 10-13 C night; fertilize every 3-4 months; cactus mix or soil/peat/coarse sand; mealybugs, spider mites, root rot.","url":"https://hgic.clemson.edu/factsheet/jade-plant/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC, ''Jade Plant'' — daytime 65-75 F (18-24 C), night 50-55 F (10-13 C); liquid houseplant fertilizer every 3-4 months.","url":"https://hgic.clemson.edu/factsheet/jade-plant/","field":"temperatureProfile"},{"citation":"University of Wisconsin-Madison Extension Horticulture, ''Jade Plant, Crassula ovata'' — four or more hours of direct sun; water liberally in active growth letting soil dry between deep waterings, keep mostly dry in winter; fertilize every two months during active growth; high-porosity succulent/cactus mix; survives light frost but freezing kills it; grows well in restricted container root space; mealybugs and spider mites.","url":"https://hort.extension.wisc.edu/articles/jade-plant-crassula-ovata/","field":"feedingProfile"},{"citation":"University of Wisconsin-Madison Extension Horticulture, ''Jade Plant, Crassula ovata'' — well-drained high-porosity succulent/cacti potting mix with extra perlite or sharp sand; repot every 2-3 years; tolerates being root-bound for years.","url":"https://hort.extension.wisc.edu/articles/jade-plant-crassula-ovata/","field":"containerProfile"},{"citation":"Missouri Botanical Garden Plant Finder, Crassula ovata — USDA zones 11-12; allow soils to dry between waterings (indoors typically every 2-3 weeks); intolerant of moist poorly drained soils; bright light with some afternoon shade; well-drained loamy potting mix; appreciates reduced-watering rest from fall to late winter; aphids, scale, spider mites, mealybugs.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=279445","field":"wateringProfile"},{"citation":"RHS Plant Profile, Crassula ovata (jade plant) — hardiness H2 (minimum 1-5 C, does not survive freezing); full sun, sheltered, south/west-facing; bushy succulent evergreen sub-shrub to 1.5-2.5 m; water to keep lightly moist in growth, very sparingly in winter dormancy; general liquid fertilizer monthly spring-summer; pots of cactus compost.","url":"https://www.rhs.org.uk/plants/4739/crassula-ovata/details","field":"temperatureProfile"},{"citation":"The Old Farmer''s Almanac, ''Jade Plant Care Guide'' — at least 6 hours of bright light daily (young plants indirect, established plants tolerate direct sun); room temperature 18-24 C, cooler at night/winter down to 13 C; let soil dry thoroughly between waterings; very susceptible to rot.","url":"https://www.almanac.com/plant/jade-plants","field":"lightProfile"},{"citation":"Confidence note: container volumes are estimates — no extension source gives pot liters; 2 L (~15 cm pot) minimum chosen because UW-Madison Extension notes jade grows well in restricted container root space and tolerates being root-bound, with heavier/larger pots (up to ~10 L) for mature top-heavy specimens per Clemson HGIC.","field":"confidence"},{"citation":"Confidence note: baseIntervalDays 14 is a conservative midpoint of the ''every 2-3 weeks indoors, soil dry between waterings'' guidance (Missouri Botanical Garden / extension consensus); hotWeatherMultiplier 0.75 and heatStressC 32 are estimates from the general guidance to water more liberally in active warm-season growth and to shade from intense afternoon sun.","field":"confidence"},{"citation":"Confidence note: seasonality months derive from Missouri Botanical Garden''s ''resting period with reduced watering from fall to late winter'' and RHS/extension spring-summer active-growth feeding guidance, mapped to Northern Hemisphere months.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('echeveria-elegans', 'Echeveria elegans', array['Echeveria','Mexican Snowball','Mexican Snow Ball','Mexican Gem','White Mexican Rose','Mexican Hens and Chicks']::text[], 'succulent', 'rosette', false, null, 0, '{"baseIntervalDays":14,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.7,"rainSkipThresholdMm":5}'::jsonb, '{"baseIntervalDays":60,"preferredNpk":"balanced liquid fertiliser, diluted; RHS advises applying only 2-3 times across the growing season"}'::jsonb, '{"recommendedMinLiters":1,"idealMinLiters":1,"idealMaxLiters":4,"soilMixTags":["well-drained","gritty","cactus-succulent-mix","loam-based-with-added-grit","shallow-container"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":1,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"productiveMonths":[2,3,4,5,6],"dormancyMonths":[11,12,1]}'::jsonb, array['Overwatering is the most common and most serious problem — the species prefers dry, well-drained conditions and rots readily in soggy soil; let the mix dry out fully between waterings and use a shallow pot with drainage holes','Frost-sensitive (RHS hardiness H2, ~1-5 C minimum): does not survive being frozen, so overwinter indoors or under glass in cold climates; NCSU/MoBot list it as hardy only in USDA zones 9a-11b','Withhold water almost entirely during winter dormancy to avoid rot in cool, low-light conditions','Monitor for mealybugs, aphids, and vine weevils','Grown as a small shallow-container or houseplant succulent; the recommendedMinLiters of ~1 L reflects its compact rosette (height to ~10 cm) rather than a large pot — clumping offsets (''pups'') can be divided into more pots over time','Etiolation (stretching, loss of tight rosette form) in too little light — give bright light or full sun']::text[], 0.5, '[{"citation":"North Carolina State Extension Gardener Plant Toolbox — Echeveria elegans (Mexican Snowball / White Mexican Rose): full sun (6+ h) to partial shade (2-6 h); prefers dry, well-drained soil with overwatering the most common problem; USDA hardiness 9a-11b; rosette-shaped clumps, slow growth, leaves 1-3 in; blooms winter to spring; propagate by division, leaf cuttings, offsets; pests mealybugs, aphids, vine weevils; no significant diseases; grown as a houseplant in shallow containers","url":"https://plants.ces.ncsu.edu/plants/echeveria-elegans/","field":"lightProfile"},{"citation":"North Carolina State Extension Gardener Plant Toolbox — Echeveria elegans: prefers dry conditions, well-drained soil, most common issue is overwatering; USDA zones 9a-11b; pests mealybugs, aphids, vine weevils","url":"https://plants.ces.ncsu.edu/plants/echeveria-elegans/","field":"wateringProfile"},{"citation":"North Carolina State Extension Gardener Plant Toolbox — Echeveria elegans: USDA hardiness zones 9a-11b; thrives in subtropical climates such as Southern California","url":"https://plants.ces.ncsu.edu/plants/echeveria-elegans/","field":"temperatureProfile"},{"citation":"RHS — Echeveria elegans (Mexican snow ball): hardiness H2 (tolerant of low temperatures but not surviving being frozen, 1 to 5 C); full sun, south- or west-facing sheltered position; loam-based medium with added grit, well-drained, pH acid/alkaline/neutral; water moderately in growth and not at all when dormant; ultimate height ~10 cm, spread 0.1-0.5 m, maturity 2-5 years; no pruning; container/patio cultivation; propagate by seed, root/stem/leaf cuttings; mealybugs, aphids, vine weevils","url":"https://www.rhs.org.uk/plants/6226/echeveria-elegans/details","field":"temperatureProfile"},{"citation":"RHS — Echeveria elegans: grow in loam-based potting medium with added grit; water moderately when in growth and not at all when dormant; apply a balanced liquid fertiliser 2 or 3 times in the growing season; well-suited to containers/patios","url":"https://www.rhs.org.uk/plants/6226/echeveria-elegans/details","field":"feedingProfile"},{"citation":"RHS — Echeveria elegans: loam-based, grit-added, well-drained growing medium; ultimate height ~10 cm and spread 0.1-0.5 m support a small, shallow container","url":"https://www.rhs.org.uk/plants/6226/echeveria-elegans/details","field":"containerProfile"},{"citation":"Confidence note: wateringProfile.baseIntervalDays=14 is a conservative ''soak-and-dry'' estimate for a succulent — neither NCSU nor RHS gives an interval in days (RHS only says ''water moderately in growth, not at all when dormant''; NCSU says it prefers dry conditions and overwatering is the main risk). hotWeatherMultiplier=0.7 and rainSkipThresholdMm=5 are planner estimates, not stated by any source","field":"confidence"},{"citation":"Confidence note: feedingProfile.baseIntervalDays=60 is derived from RHS''s ''balanced liquid fertiliser 2 or 3 times in the growing season'' (≈3 feeds over a ~6-month growing season). containerProfile liters (recommendedMin 1 L, ideal 1-4 L) are converted from RHS''s ~10 cm height / 0.1-0.5 m spread and NCSU''s ''shallow container'' guidance rather than an explicit pot volume","field":"confidence"},{"citation":"Confidence note: temperatureProfile.coldHardyMinC=1 takes the conservative warm end of RHS hardiness H2 (1-5 C, ''not surviving being frozen'') to protect the plant, even though NCSU/MoBot list USDA 9a-11b (9a ≈ -6.7 C); frostSensitive=true. heatStressC=38 is an estimate (no source states an upper heat limit); productiveMonths/dormancyMonths approximate NCSU''s winter-to-spring bloom and RHS''s winter dormancy note","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('ficus-carica', 'Ficus carica', array['Fig','Common Fig','Edible Fig']::text[], 'fruit', 'tree', false, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":2,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"preferredNpk":"high-potassium liquid (e.g. 5-10-10 or kelp); balanced 8-8-8 / 10-10-10 in ground"}'::jsonb, '{"recommendedMinLiters":30,"idealMinLiters":40,"idealMaxLiters":60,"soilMixTags":["soil-based","free-draining","fine-bark-added","organically-rich"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-9,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"productiveMonths":[6,7,8,9],"dormancyMonths":[12,1,2]}'::jsonb, array['Container minimum (30 L) reflects that mature figs are 3-6 m trees grown in-ground; in pots figs actually fruit better with restricted roots, so avoid overpotting and repot only into a slightly larger container every couple of years (RHS).','Drought-sensitive: yellowing leaves and wilting signal under-watering; container figs and restricted-root plants can need daily checks in hot, dry weather (Clemson, RHS).','Frost-sensitive: significant die-back below about -9 C / 15 F; in cold zones (5-7) plant against a south-facing wall, mulch roots, or move container plants into an unheated shelter over winter (Missouri Botanical Garden, RHS).','Most cultivars recommended for home growing are parthenocarpic and self-fruitful; do NOT buy wild/Smyrna types that need fig-wasp (caprification) pollination (Clemson, Missouri Botanical Garden).','Over-feeding nitrogen, especially in colder regions, reduces cold hardiness and promotes leaf over fruit (Clemson).']::text[], 0.2, '[{"citation":"Missouri Botanical Garden Plant Finder — Ficus carica (Edible Fig): USDA zones 6-9 (best 8-10), full sun to part shade, medium water, organically rich moist well-drained soil, self-fruitful/parthenocarpic, winter protection needed below 15 F, mature 10-20 ft, fruit late summer/fall.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=282762","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden Plant Finder — Ficus carica: self-fruitful, most cultivars parthenocarpic (set fruit without cross-pollination).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=282762","field":"selfFruitful"},{"citation":"Clemson HGIC — Figs: How to Grow and Care for Figs in South Carolina: full sun (8 hours or more daily) required during the growing season.","url":"https://hgic.clemson.edu/factsheet/figs-how-to-grow-and-care-for-figs-in-south-carolina/","field":"lightProfile"},{"citation":"Clemson HGIC — Figs: about 1 inch (25 mm) of water per week from rain or irrigation is adequate; more in hot dry periods; yellowing/wilting indicates drought stress.","url":"https://hgic.clemson.edu/factsheet/figs-how-to-grow-and-care-for-figs-in-south-carolina/","field":"wateringProfile"},{"citation":"Clemson HGIC — Figs: mature in-ground plants fed balanced 8-8-8 or 10-10-10 three times yearly (early April, early June, mid-July); colder-region plants fed less to preserve cold hardiness; common SC cultivars are self-fertile (female flowers, set fruit without cross-pollination).","url":"https://hgic.clemson.edu/factsheet/figs-how-to-grow-and-care-for-figs-in-south-carolina/","field":"feedingProfile"},{"citation":"RHS — How to grow figs: feed container figs with an organic high-potassium liquid fertiliser fortnightly (every ~14 days) throughout the growing season until figs ripen in late summer.","url":"https://www.rhs.org.uk/fruit/figs/grow-your-own","field":"feedingProfile"},{"citation":"RHS — How to grow figs: start young figs in a pot ~30 cm (1 ft) wide and deep; figs fruit better with restricted roots so avoid overpotting and repot only into a slightly larger soil-based container every couple of years; keep evenly moist, checking daily in hot dry weather; position in a warm sunny south-facing spot; move container figs under cover or wrap them over winter (frost-sensitive).","url":"https://www.rhs.org.uk/fruit/figs/grow-your-own","field":"containerProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Ficus carica (Common Fig): grow in full sun; large fruit/ornamental tree habit; container culture in colder areas with overwintering indoors.","url":"https://plants.ces.ncsu.edu/plants/ficus-carica/","field":"growthHabit"},{"citation":"Confidence note — recommendedMinLiters (30 L), idealMin/Max (40/60 L), heatStressC (38 C), hotWeatherMultiplier (2), and rainSkipThresholdMm (25, from Clemson''s 1 inch/week) are conservative app estimates. Extension sources give pot size in diameter (RHS ~30 cm starter pot ≈ 14 L; figs are otherwise large in-ground 3-6 m trees) and water as ~1 inch/week rather than an exact pot volume or interval; no source gives a numeric upper heat-stress temperature. Values chosen for a realistic productive container fig that intentionally keeps roots somewhat restricted per RHS.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('haworthia-attenuata', 'Haworthia attenuata', array['Haworthia','Zebra Plant','Zebra Haworthia','Zebra Cactus']::text[], 'succulent', 'rosette', false, null, 0, '{"baseIntervalDays":14,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.75}'::jsonb, '{"baseIntervalDays":90,"preferredNpk":"half-strength low-nitrogen succulent fertilizer, growing season only (RHS: once or twice per season)"}'::jsonb, '{"recommendedMinLiters":0.5,"idealMinLiters":0.5,"idealMaxLiters":2,"soilMixTags":["cactus-succulent-mix","well-draining","added-perlite-or-grit","shallow-pot-preferred"]}'::jsonb, '{"targetSunHours":5,"minSunHours":3,"maxSunHours":6}'::jsonb, '{"coldHardyMinC":4,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"dormancyMonths":[11,12,1,2]}'::jsonb, array['Root rot from overwatering — let soil dry fully between waterings and keep almost dry in winter','Leaf scorch from hot direct sun — prefers bright light with protection from intense midday sun','Fading of the white leaf banding/pattern under inadequate light','Mealybugs and scale insects','Leaf spot and fungal disease if foliage stays wet or soil is kept soggy']::text[], 0.2, '[{"citation":"North Carolina Extension Gardener Plant Toolbox — Haworthiopsis attenuata (Zebra Haworthia): allow soil to dry between waterings; bright indirect light; well-draining cactus/succulent mix; USDA zones 9-11; thrives 60-80 F, avoid below 50 F; rosette clumping habit; root rot, leaf spot, scale, mealybugs","url":"https://plants.ces.ncsu.edu/plants/haworthiopsis-attenuata/","field":"wateringProfile"},{"citation":"University of Wisconsin-Madison Horticulture Extension — ''Haworthias: Super Succulents for Small Spaces'': water weekly in summer, less in winter, soil dry between waterings; a few hours of direct light in east/west window plus bright indirect; clusters fit 4-5 inch pots, shallow pots preferred, do not oversize; optimal 75-90 F, tolerates low 40s to low 100s F, no frost; potting soil cut 1:1 with perlite/grit/pumice","url":"https://hort.extension.wisc.edu/articles/haworthias-super-succulents-for-small-spaces/","field":"containerProfile"},{"citation":"RHS — Haworthia attenuata (zebra plant): grow in cactus compost in full light with protection from hot sun; water moderately in growth, keep almost dry in winter (dormant period); half-strength low-nitrogen fertiliser once or twice in the growing season; hardiness H2 (tolerates 1-5 C, will not survive freezing); mealybugs; overwatering is the primary risk","url":"https://www.rhs.org.uk/plants/8268/haworthia-attenuata/details","field":"feedingProfile"},{"citation":"University of Wisconsin-Madison Horticulture Extension — light guidance (a few hours direct sun daily plus bright indirect; tolerates lower light than most succulents) used to set target/min/max sun hours","url":"https://hort.extension.wisc.edu/articles/haworthias-super-succulents-for-small-spaces/","field":"lightProfile"},{"citation":"RHS hardiness H2 (1-5 C minimum) and UW-Madison tolerance range (low 40s F to low 100s F) used for coldHardyMinC=4 and heatStressC=38; frost-sensitive per both sources and NC State (zones 9-11, not frost tolerant)","url":"https://www.rhs.org.uk/plants/8268/haworthia-attenuata/details","field":"temperatureProfile"},{"citation":"Confidence note: sources give qualitative guidance, not exact numbers. baseIntervalDays=14 is a conservative reading of UW-Madison ''weekly in summer, less in winter'' combined with universal ''let soil dry fully / overwatering is the primary risk'' warnings. feedingProfile.baseIntervalDays=90 converts RHS ''once or twice per growing season''. Container liters converted from UW-Madison 4-5 inch pot guidance (~0.5-2 L). Sun hours estimated from qualitative ''few hours direct + bright indirect''. Treat these four fields as estimated.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('malus-domestica', 'Malus domestica', array['Apple','Orchard apple','Domestic apple']::text[], 'fruit', 'tree', false, false, 1, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"preferredNpk":"high-potassium (e.g. 5-5-10) for containers; general-purpose granular in early spring for in-ground"}'::jsonb, '{"recommendedMinLiters":38,"idealMinLiters":45,"idealMaxLiters":90,"soilMixTags":["loam-based","well-drained","slightly-acidic-ph-6.0-6.5","peat-free-compost"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":14}'::jsonb, '{"coldHardyMinC":-34,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"4":[{"startMonth":4,"endMonth":5}],"5":[{"startMonth":3,"endMonth":5}],"7":[{"startMonth":2,"endMonth":4},{"startMonth":11,"endMonth":12}]},"productiveMonths":[8,9,10,11],"dormancyMonths":[12,1,2]}'::jsonb, array['Apple is a deciduous tree (standard trees reach 4.5-9 m / 15-30 ft); in-ground planting is strongly preferred. For containers use only a dwarfing rootstock (e.g. M27, M9, M26); the recommendedMinLiters (38 L) is a realistic dwarf-apple container minimum, not a size for standard or semi-dwarf trees.','Most apple varieties are self-unfruitful and set only a small crop with their own pollen; plant at least one compatible second variety (or a flowering crabapple) with an overlapping bloom period within ~15-30 m (50-100 ft) for a good crop.','Late spring frosts damage open flowers and reduce fruit set; choose a sheltered, non-frost-pocket site and consider late-flowering varieties in cold areas.','Container trees dry out fast and may need watering daily in hot weather; keep compost evenly moist but never waterlogged (root rot risk).','Most classic apple varieties are high-chill (need roughly 800+ hours below ~6 C / 45 F); low-chill needs vary by cultivar and climate.']::text[], 0.2, '[{"citation":"North Carolina Extension Gardener Plant Toolbox — Malus domestica (Apple): full sun (6+ hours direct sun) to partial shade; USDA hardiness zones 4a-9b; slightly acidic, moist, well-drained soil (pH 6.0-6.5); deciduous tree 15-30 ft mature height; grafted dwarf rootstocks much smaller.","url":"https://plants.ces.ncsu.edu/plants/malus-domestica/","field":"lightProfile"},{"citation":"North Carolina Extension Gardener Plant Toolbox — Malus domestica: USDA hardiness zones 4a-9b. Zone 4a average annual minimum temperature is about -34 C (-30 F), used as coldHardyMinC for cold-hardy cultivars.","url":"https://plants.ces.ncsu.edu/plants/malus-domestica/","field":"temperatureProfile"},{"citation":"Iowa State University Extension and Outreach — Pollination requirements for tree and small fruits: apples are self-unfruitful (most varieties set only a small crop with their own pollen); plant at least two different varieties with overlapping bloom for cross-pollination; flowering crabapples can pollinate nearby apples; space cross-pollinating trees within 50-100 ft.","url":"https://yardandgarden.extension.iastate.edu/how-to/pollination-requirements-tree-and-small-fruits","field":"pollinationPartnersRequired"},{"citation":"RHS — How to grow apples (grow your own): full sun, warm sheltered site not prone to late frosts which damage flowers; container apples on M9/M26 dwarf rootstock need a pot at least 45 cm (18 in) diameter with loam-based peat-free compost; keep compost evenly moist, water regularly in dry spells; feed containers with high-potassium liquid fertiliser every fortnight in the growing season; in-ground trees in regularly mulched soil generally need no extra feeding.","url":"https://www.rhs.org.uk/fruit/apples/grow-your-own","field":"feedingProfile"},{"citation":"RHS — How to grow apples: container apples on dwarf rootstock need a pot of at least 45 cm (18 in) diameter; a ~45 cm cube/round pot is roughly 38-45 L, used for recommendedMin/idealMin container volume. Frost damages open flowers (frostSensitive).","url":"https://www.rhs.org.uk/fruit/apples/grow-your-own","field":"containerProfile"},{"citation":"RHS — How to grow apples: keep container compost evenly moist and water regularly in dry spells; apples do not tolerate prolonged drought but dislike waterlogging. baseIntervalDays (3) and hotWeatherMultiplier reflect ''evenly moist'' for an established in-ground/large-container tree; container trees may need more frequent watering (daily in heat).","url":"https://www.rhs.org.uk/fruit/apples/grow-your-own","field":"wateringProfile"},{"citation":"Confidence note: schema numeric watering interval (baseIntervalDays=3) and hotWeatherMultiplier are conservative estimates. RHS and NCSU specify ''evenly moist / regular watering'' qualitatively rather than a day interval, and actual frequency depends heavily on rootstock, in-ground vs container, soil and climate (container trees can need daily watering in heat). Treated as an estimate.","url":"https://www.rhs.org.uk/fruit/apples/grow-your-own","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('passiflora-edulis', 'Passiflora edulis', array['Passion fruit','Purple passion fruit','Purple granadilla']::text[], 'fruit', 'climbing', true, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.6}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"preferredNpk":"balanced during growth; switch to higher-potassium/lower-nitrogen at flowering"}'::jsonb, '{"recommendedMinLiters":95,"idealMinLiters":95,"idealMaxLiters":150,"soilMixTags":["well-drained","loam-based","rich-in-organic-matter","ph-6-7.5"]}'::jsonb, '{"targetSunHours":6,"minSunHours":6,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-3,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Frost-tender: mature vines may die back to the ground after exposure to the mid-20s F (around -4 C); needs protection or overwintering below freezing.','Drought-sensitive shallow roots — drought reduces growth, flowering and fruit set and increases Fusarium susceptibility; keep soil evenly moist but never saturated.','Overwatering / poor drainage promotes Fusarium wilt, Phytophthora root/crown rot and nematode damage; productive lifespan is often only 3-4 years before replanting.','Vigorous tendril climber to ~10 m — needs a strong trellis, fence or wired wall that can withstand wind.','In containers, start in roughly a 30 cm (about 28 L) pot and pot up; the 95 L+ minimum reflects a mature fruiting vine, which is best grown in the largest practical container or in-ground.','Pests: spider mites (can defoliate), caterpillars/Lepidoptera larvae, stink bugs, aphids, snails and root-knot nematodes; viral woodiness disease deforms fruit.']::text[], 1, '[{"citation":"UF/IFAS Extension, HS1406 ''The Passion Fruit in Florida'' — optimal 65-90 F, cold death in the mid-20s F, chilling injury below 59 F, USDA zone 9b+, full sun, small-but-frequent irrigation with drought/flood sensitivity, well-drained soil pH ~6-7.5, strong wind-resistant trellis, purple types self-compatible, peak production midsummer-fall, 3-4 year productive life.","url":"https://ask.ifas.ufl.edu/publication/HS1406","field":"temperatureProfile,lightProfile,wateringProfile,containerProfile,seasonality,requiresSupport,selfFruitful,commonIssues"},{"citation":"UC ANR Cooperative Extension Ventura County, ''Passion Fruit'' — optimal 68-82 F, purple variety frost-tender, requires a lot of water but overwatering promotes disease, frequent balanced fertilizer during the growing season, trained on strong supports like grapes on 8-12 ft centers, purple flowers self-compatible, fast-draining sandy loam pH 6.5-7, susceptible to fusarium wilt/nematodes/crown rot (replant every 3-4 years).","url":"https://ucanr.edu/county/cooperative-extension-ventura-county/passion-fruit","field":"temperatureProfile,wateringProfile,feedingProfile,requiresSupport,commonIssues"},{"citation":"RHS ''How to grow passion flowers'' growing guide — container culture starting in a 30 cm (12 in) pot, water thoroughly when surface is dry / weekly in dry spells and less in winter, feed every 4-6 weeks during the growing season (Mar-Oct) with no winter feeding, climbs via tendrils on a trellis/wired wall to ~10 m, edible types need a 10-16 C minimum.","url":"https://www.rhs.org.uk/plants/passion-flower/growing-guide","field":"containerProfile,wateringProfile,feedingProfile,verticalSuitability,temperatureProfile"},{"citation":"Confidence note — coldHardyMinC set to -3 C as a conservative damage threshold: UF/IFAS reports mature-vine aboveground death in the mid-20s F (about -4 C) but chilling injury already below 59 F, so this single number compresses a sensitivity range. heatStressC (32 C) derived from the 90 F optimal-range ceiling combined with UC ANR''s note that inland plants dislike hot dry heat. Container idealMin/MaxLiters (95-150 L) are reasoned estimates for a mature in-container vine extrapolated from the RHS 30 cm starter pot and the species'' in-ground vigor; no extension source gives an exact liter figure.","url":"https://ask.ifas.ufl.edu/publication/HS1406","field":"confidence"}]'::jsonb, 2, '2026-06-02'),
  ('physalis-philadelphica', 'Physalis philadelphica', array['Tomatillo','Mexican husk tomato','Husk tomato']::text[], 'fruit', 'bush', true, false, 2, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":10,"fruitingIntervalDays":14,"preferredNpk":"balanced, low-to-moderate nitrogen (e.g. 5-10-10)"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-drained","rich-loam","neutral-pH"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":13,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":5,"endMonth":6}],"8":[{"startMonth":4,"endMonth":5}]},"productiveMonths":[7,8,9,10]}'::jsonb, array['Not self-fertile: grow at least two plants for cross-pollination or fruit will not set (UMN, Almanac).','Plants reach 3-4 ft and sprawl; cage, stake or trellis to keep fruit off the soil.','Wet foliage and soil splash spread disease; water at the base, not overhead.','Reduce watering frequency once fruit has set to improve fruit quality.','Flowers abort above ~32C (90F) or below ~13C (55F); protect from heat and cold snaps.','Susceptible to early/late blight, anthracnose, powdery mildew, tobacco mosaic virus; rotate away from other nightshades (tomato, pepper, potato) for ~3 years.','Pests: cutworms, tomato hornworms, Colorado potato beetles.','Container growing needs a pot at least 30 cm (12 in) deep and more frequent watering than in-ground plants.']::text[], 0.3, '[{"citation":"University of Minnesota Extension — Growing tomatillos and ground cherries in home gardens (6-8 hrs sun; transplant after frost; water at base, even moisture; not self-fertile, grow more than one plant; cage/trellis support; balanced nitrogen, excess N delays fruiting; pests early/late blight, anthracnose, TMV, cutworms, hornworms, Colorado potato beetle; 12-in deep containers).","url":"https://extension.umn.edu/vegetables/growing-tomatillos-and-ground-cherries","field":"lightProfile,wateringProfile,feedingProfile,containerProfile,commonIssues,pollination,requiresSupport"},{"citation":"The Old Farmer''s Almanac — Tomatillos: How to Plant, Grow, and Care for Tomatillo (spacing ~3 ft; ~1 inch rain/water per week, water once or twice a week; withstands drought and heat; not self-fertile, grow more than one plant; trellis/cage support; flowers abort above 90F/below 55F).","url":"https://www.almanac.com/plant/tomatillos","field":"wateringProfile,temperatureProfile,pollination,requiresSupport"},{"citation":"UC Master Gardener Program of Alameda County — Guide to Growing Tomatillos (at least 6 hours sun/day; plants grow up to 4 ft, need cage or stake support; reduce irrigation after fruit set; plant at least two of same variety for pollination; balanced fertilizer; susceptible to powdery mildew and nightshade diseases).","url":"https://ucanr.edu/site/uc-master-gardener-program-alameda-county/article/guide-growing-tomatillos","field":"lightProfile,requiresSupport,wateringProfile,feedingProfile,commonIssues"},{"citation":"Missouri Botanical Garden Plant Finder — Physalis ixocarpa (full sun; medium water, water regularly; 2.5-3.5 ft tall by 3-4 ft wide; USDA zones 8-10 as annual; sow after frost when night temps >=55F; subject to Solanaceae pests/diseases, avoid same site for 3 years).","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=287199","field":"lightProfile,wateringProfile,temperatureProfile,commonIssues,seasonality"},{"citation":"Confidence note — feeding cadence (baseIntervalDays 10, fruitingIntervalDays 14, NPK) is conservative: sources specify a balanced fertilizer with low-to-moderate nitrogen and warn excess N delays fruit, but give no exact day interval. Container idealMaxLiters (38 L) is an estimate scaled to a 3-4 ft bushy plant; sources state a 12-in-deep pot minimum but no upper volume. hotWeatherMultiplier and rainSkipThresholdMm derived from the ~1 inch/week + heat-tolerance guidance, not a published per-day figure. Planting windows by zone generalized from frost-date guidance.","field":"confidence"}]'::jsonb, 2, '2026-06-02'),
  ('prunus-avium', 'Prunus avium', array['Cherry','Sweet cherry','Wild cherry','Gean']::text[], 'fruit', 'tree', false, true, 0, '{"baseIntervalDays":10,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"preferredNpk":"low-nitrogen / high-potassium (e.g. 5-10-10 in spring; high-K liquid feed for containers)"}'::jsonb, '{"recommendedMinLiters":90,"idealMinLiters":90,"idealMaxLiters":120,"soilMixTags":["loam-based","well-drained","slightly-acidic","fertile"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-20,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[6,7],"dormancyMonths":[11,12,1,2]}'::jsonb, array['In-ground cherry trees reach 4.5-9 m tall; container culture requires a dwarfing rootstock such as ''Gisela 5'' and a pot at least 45-50 cm wide and deep (~90 L). The recommendedMinLiters reflects this minimum dwarf-container size, not a full standard tree, which must be grown in the ground.','No tolerance for wet or poorly drained soils; overwatering and waterlogging cause root rot and crown gall.','Heavy rain or excessive irrigation near harvest causes fruit cracking/splitting.','Spring frosts during blossom can destroy the crop; protect flowers from late frosts.','Disease-prone: bacterial canker, brown rot, cherry leaf spot/scorch, silver leaf, black knot, powdery mildew, shot-hole.','Pests: birds and squirrels strip fruit (use netting), plus aphids, spotted wing drosophila / cherry fruit flies, peach tree borer, scale.','Self-fertile cultivars (e.g. ''Stella'', ''Lapins'', ''Sweetheart'') fruit alone, but most older sweet cherries need a compatible pollinizer that blooms at the same time, planted within ~15-30 m; even self-fertile types crop more heavily with a partner.','Requires roughly 800-1200 winter chill hours below ~7 C to break dormancy and fruit.']::text[], 0.2, '[{"citation":"Missouri Botanical Garden, Plant Finder: Prunus avium — USDA zones 3-8, full sun to part shade, medium moisture, no tolerance for wet soils, white flowers in April, small sweet red-to-black cherries ripen early summer; lists leaf spot, bacterial canker, brown rot, black knot, crown gall, leaf curl/scorch, powdery mildew, root rot, scab, shot-hole, plus aphids/fruit flies/sawflies/scale and bird/squirrel pressure.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=l860","field":"temperatureProfile"},{"citation":"Missouri Botanical Garden, Plant Finder: Prunus avium — full sun to part shade; well-drained soil with no tolerance for wet soils.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=l860","field":"lightProfile"},{"citation":"Missouri Botanical Garden, Plant Finder: Prunus avium — extensive disease/pest list and note that cold winter temperatures and spring frosts cause significant injury to buds/flowers.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?kempercode=l860","field":"commonIssues"},{"citation":"RHS, How to grow cherries — sunny south/south-west position; deep, fertile, well-drained slightly acidic soil pH 6.5-6.7; water newly planted trees in dry spells for the first year, established trees generally need no extra water; avoid overwatering in summer (causes fruit splitting); feed established mulched trees little, or granular fertiliser in early spring; container trees fed fortnightly with high-potassium liquid feed April-August.","url":"https://www.rhs.org.uk/advice/profile?pid=318","field":"wateringProfile"},{"citation":"RHS, How to grow cherries — feeding regime: granular fertiliser in early spring; containers fortnightly high-potassium liquid feed April-August; prune after harvest (late July/August).","url":"https://www.rhs.org.uk/advice/profile?pid=318","field":"feedingProfile"},{"citation":"RHS, How to grow cherries — container growing possible on semi-dwarfing rootstock ''Gisela 5'' in a pot at least 45-50 cm (18-20 in) wide and deep using loam-based compost.","url":"https://www.rhs.org.uk/advice/profile?pid=318","field":"containerProfile"},{"citation":"RHS, How to grow cherries — many modern sweet cherries are self-fertile; others need a compatible partner flowering at the same time; ripens early summer onwards; pests/diseases include birds, silver leaf, bacterial canker, brown rot, leaf scorch, spotted wing drosophila.","url":"https://www.rhs.org.uk/advice/profile?pid=318","field":"selfFruitful"},{"citation":"RHS, Prunus avium ''Stella'' (F) — self-fertile sweet cherry; full sun, south/west aspect; RHS hardiness H6 (-20 to -15 C); cropping season late July; reaches 2.5-4 m in 5-10 years; fruit prone to splitting in wet weather.","url":"https://www.rhs.org.uk/plants/59056/prunus-avium-stella-(f)/details","field":"temperatureProfile"},{"citation":"RHS, Prunus avium ''Stella'' (F) — self-fertile cultivar example; late-July cropping; spring white flowers.","url":"https://www.rhs.org.uk/plants/59056/prunus-avium-stella-(f)/details","field":"seasonality"},{"citation":"Penn State Extension, Cherries in the Garden and the Kitchen — full sun; USDA zones 5-9; most sweet cherries need a different compatible cultivar nearby though several newer cultivars are self-fruitful (all crop better with a second cultivar); sweet and tart cherries cannot pollinate each other; diseases include cherry leaf spot, powdery mildew, rhizopus rot, bacterial canker; pests include cherry/black cherry fruit flies, peach tree borer, plum curculio, birds and mammals; fruit cracks with excessive rainfall near harvest.","url":"https://extension.psu.edu/cherries-in-the-garden-and-the-kitchen","field":"selfFruitful"},{"citation":"UC IPM (UC ANR), Cultural Tips for Growing Cherry — full sun, good air movement, well-drained slightly acidic sandy loam at least 4 ft deep, no tolerance for poorly drained soil; young trees up to 3-5 gallons of water per week; established trees irrigated deeply every 2-3 weeks (12-24 h) rather than frequent shallow watering; apply nitrogen annually in the growing season (mature trees ~3-5 lb ammonium sulfate or 2 lb urea); cherries require 800-1200 chill hours below 45 F.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-cherry/","field":"wateringProfile"},{"citation":"UC IPM (UC ANR), Cultural Tips for Growing Cherry — nitrogen applied annually during the growing season; chill requirement 800-1200 hours below 45 F.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-cherry/","field":"feedingProfile"},{"citation":"Confidence note: baseIntervalDays (watering=10, feeding=14) and hotWeatherMultiplier/rainSkipThresholdMm are conservative app-cadence values interpolated from qualitative guidance. Sources give young-tree weekly watering (UC IPM 3-5 gal/week) and established deep watering every 2-3 weeks (UC IPM), with established in-ground trees often needing no supplemental water (RHS); 10 days is a middle-ground default for a managed/container tree. Feeding 14 days follows RHS fortnightly container feeding; in-ground feeding is effectively annual in early spring. heatStressC (35) is an estimate — no source gave an explicit upper-temperature stress threshold. verticalSuitability is low (tree habit, not trellis/hanging).","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('prunus-domestica', 'Prunus domestica', array['Plum','European plum','Common plum','Prune plum']::text[], 'fruit', 'tree', false, true, 0, '{"baseIntervalDays":7,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"preferredNpk":"high-potassium liquid feed (e.g. 5-5-10) every fortnight for containers; in-ground trees rarely need feeding if mulched (apply nitrogen in early spring only when annual shoot growth is under ~20 cm / 8 in)"}'::jsonb, '{"recommendedMinLiters":90,"idealMinLiters":100,"idealMaxLiters":125,"soilMixTags":["loam-based","well-drained","fertile","slightly-acidic-ph-6.0-6.5","peat-free-compost"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":14}'::jsonb, '{"coldHardyMinC":-29,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"4":[{"startMonth":4,"endMonth":5}],"5":[{"startMonth":3,"endMonth":5}],"8":[{"startMonth":11,"endMonth":12},{"startMonth":1,"endMonth":3}]},"productiveMonths":[7,8,9],"dormancyMonths":[12,1,2]}'::jsonb, array['Plum is a deciduous tree; in-ground planting in a warm, sunny, sheltered spot is strongly preferred. For containers choose a compact/dwarfing variety; the recommendedMinLiters (90 L) reflects the RHS minimum pot of about 50 cm wide and 50 cm deep (~98 L for that volume) and is not a size for a standard or semi-dwarf tree.','Plums have little tolerance for wet, heavy or waterlogged soils and develop root-rotting diseases easily; water deeply but infrequently and never leave containers standing in water (overwaterRisk is high).','Most European plums (e.g. ''Victoria'', ''Stanley'', ''Mount Royal'') are self-fertile, but fruit set and yield usually improve with a compatible European-plum pollinator flowering at the same time. European plums (Prunus domestica) and Japanese plums (Prunus salicina) generally do not cross-pollinate each other.','Blossoms open very early in spring and are easily killed by late frost, which can destroy an entire season''s crop; choose a non-frost-pocket site and protect with fleece when frost is forecast.','European plums are relatively high-chill (roughly 700-1000 hours below ~7 C / 45 F), so they fruit poorly in mild-winter climates that do not meet their chilling requirement.','Container trees dry out far faster than in-ground trees and may need watering several times a week (even daily) in hot, dry weather despite the 7-day in-ground base interval.']::text[], 0.1, '[{"citation":"RHS — How to grow plums (grow your own): plums need a warm, sunny spot with fertile soil that does not waterlog; container plums (compact varieties such as ''Blue Tit'') need a pot at least 50 cm wide and deep with loam-based compost; water containers regularly in dry spells April-August keeping compost evenly moist but never standing in water; feed containers with high-potassium liquid fertiliser every fortnight April-August (or general-purpose granular each spring); in-ground mulched trees generally need no feeding.","url":"https://www.rhs.org.uk/fruit/plums/grow-your-own","field":"feedingProfile"},{"citation":"RHS — How to grow plums: minimum container is about 50 cm wide and 50 cm deep for compact varieties; a 50 cm-diameter, 50 cm-deep round pot is roughly 98 L, so recommendedMin/idealMin container volumes are set near that (90-125 L). Soil should be fertile, ideally slightly acidic pH 6-6.5, well-drained loam/clay that neither dries out nor waterlogs.","url":"https://www.rhs.org.uk/fruit/plums/grow-your-own","field":"containerProfile"},{"citation":"RHS — How to grow plums: blossom is vulnerable to frost in March-April (cover with fleece if frost forecast); avoid frost-prone sites. Many varieties (''Victoria'', ''Czar'', ''Warwickshire Drooper'') are self-fertile. Harvest July-September when fruit is fully coloured and soft.","url":"https://www.rhs.org.uk/fruit/plums/grow-your-own","field":"seasonality"},{"citation":"University of Minnesota Extension — Growing stone fruits in the home garden: European plums (Prunus domestica) are self-compatible and do not require a second variety, though cross-pollination can increase yields; stone-fruit trees need full sun for the most fruit; cold-hardy European cultivars (e.g. Mount Royal) are reliable to USDA zone 4; blossoms bloom very early and delicate flowers are easily frozen; space trees 12-20 ft apart; harvest mid-late August to early September.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"pollinationPartnersRequired"},{"citation":"University of Minnesota Extension — Growing stone fruits in the home garden: cold-hardy European plum cultivars are rated for USDA zone 4. Zone 4 average annual minimum temperature is about -34 to -29 C (-30 to -20 F); coldHardyMinC set conservatively to -29 C for typical European-plum hardiness. Blossoms are frost-sensitive.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"temperatureProfile"},{"citation":"University of Minnesota Extension — Growing stone fruits in the home garden: stone fruit trees need full sun to produce the most fruit (minimum half-day sun). targetSunHours 8 / minSunHours 6 reflect ''full sun'' (6+ hours direct sun) for a fruit tree.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"lightProfile"},{"citation":"UC Statewide IPM Program — Cultural tips for growing plum and prune: young trees need up to 3-5 gallons of water per week; established trees are irrigated every 2-3 weeks (12-24 h to wet 3-6 ft deep), more often (every 3-5 days) in sandy soils and every ~1.5-2 weeks in heavier soils. European plums require about 700-1000 chilling hours (below 45 F / 7 C). Mature trees receive ~3-5 lb ammonium sulfate or ~2 lb urea per year. Trees need at least 150 frost-free days so spring blossoms are not damaged.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-plum-and-prune/","field":"wateringProfile"},{"citation":"Confidence note: baseIntervalDays (7) is a conservative in-ground/large-container default reconciling RHS ''keep evenly moist, water regularly in dry spells'' with UC IPM ranges (young trees ~weekly 3-5 gal; established trees every 2-3 weeks; sandy soils every 3-5 days). Actual interval varies strongly with soil type, container vs ground, rootstock and climate (containers often need watering several times a week or daily in heat).","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-plum-and-prune/","field":"confidence"},{"citation":"Confidence note: heatStressC (35 C) is an estimate. The authoritative extension/RHS sources read for this profile do not state an explicit upper heat-stress temperature for Prunus domestica; the value is a conservative general fruit-tree heat-stress threshold and should be refined if a cited figure is found.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('prunus-persica', 'Prunus persica', array['Peach']::text[], 'fruit', 'tree', false, true, 0, '{"baseIntervalDays":4,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":30,"fruitingIntervalDays":30,"postHarvestIntervalDays":30,"preferredNpk":"10-10-10"}'::jsonb, '{"recommendedMinLiters":70,"idealMinLiters":70,"idealMaxLiters":95,"soilMixTags":["loam-based","well-drained","moisture-retentive"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":14}'::jsonb, '{"coldHardyMinC":-23,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"5":[{"startMonth":3,"endMonth":4}],"6":[{"startMonth":3,"endMonth":4}],"7":[{"startMonth":2,"endMonth":3}],"8":[{"startMonth":12,"endMonth":3}]},"productiveMonths":[6,7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Blooms very early in spring; blossoms are easily killed by late frosts, so site in a frost-free, sheltered spot or cover/move container trees during flowering (RHS, Clemson, UMN).','Needs sufficient winter chill (hours at or below ~7 C / 45 F) to break dormancy and set fruit; choose a cultivar matched to local chill accumulation (Clemson, Almanac).','Self-fertile but flowers early when few pollinators are active; hand-pollinate container or sheltered trees to ensure a good crop (RHS).','Container minimum of ~70 L is a practical large-pot size for a dwarf/patio peach (RHS recommends a pot at least 45 cm wide and deep, ~71 L); full-size, standard peach trees are in-ground plants and will not reach full size or yield in a container.','Prone to root problems in waterlogged soil; plant in moist but well-drained soil and avoid overwatering.','Cold hardiness varies by cultivar; hardy types (e.g. Reliance, Contender) survive to about USDA zone 4 while many cultivars are best in zones 5-8.']::text[], 0.2, '[{"citation":"Clemson Cooperative Extension, Home & Garden Information Center — Peaches & Nectarines: full-sun siting, self-fruitful (only one variety needed), 10-10-10 plus calcium nitrate fertilizer schedule for young trees, dormant planting early December to mid-March, harvest mid-June to mid-September, chill requirement (hours at 45 F / 7 F or less).","url":"https://hgic.clemson.edu/factsheet/peaches-nectarines/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension — Peaches & Nectarines: fertilizer program for peaches (10-10-10 in March, supplemental calcium nitrate in May and July for young trees), establishing the ~monthly growing-season feeding cadence and preferred balanced NPK.","url":"https://hgic.clemson.edu/factsheet/peaches-nectarines/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension — Peaches & Nectarines: peach flowers are self-fruitful, so it is not necessary to plant more than one variety.","url":"https://hgic.clemson.edu/factsheet/peaches-nectarines/","field":"selfFruitful"},{"citation":"University of Minnesota Extension — Growing stone fruits in the home garden: young fruit trees require 1-2 inches of water per week from rain or irrigation; stone fruits need at least a half day of sun (more sun = more fruit); nitrogen is the main annual nutrient; bare-root trees planted in early spring while dormant; blossoms easily damaged by spring freezes.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing stone fruits in the home garden: hardy peach cultivars (Reliance, Contender, Intrepid) can be grown in Minnesota''s colder zones (down to about zone 4), establishing the conservative cold-hardy lower limit and strong frost sensitivity of blossoms.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"temperatureProfile"},{"citation":"Royal Horticultural Society (RHS) — How to grow peaches: container peaches need a pot at least 45 cm (18 in) wide and deep with loam-based compost (about 71 L), feed container trees with high-potassium liquid feed every fortnight in the growing season or granular general-purpose feed each spring; all peach varieties are self-fertile; protect/move flowering trees from frost and hand-pollinate.","url":"https://www.rhs.org.uk/fruit/peaches/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS) — How to grow peaches: container-grown trees need a steady supply of moisture throughout the growing season and newly planted trees need regular watering in dry spells for the first couple of years; supports the container-leach feeding adjustment and frost-protection / hand-pollination guidance.","url":"https://www.rhs.org.uk/fruit/peaches/grow-your-own","field":"wateringProfile"},{"citation":"The Old Farmer''s Almanac — Peaches: Planting, Growing, and Harvesting Peach Trees: peaches grow in USDA zones 4-10 and do best in zones 6-8; trees are self-pollinating; chill hours are hours at or below 45 F (7 C) needed to break dormancy; early spring planting and summer harvest windows.","url":"https://www.almanac.com/plant/peaches","field":"seasonality"},{"citation":"Confidence note — heatStressC (35 C) and the hotWeatherMultiplier (1.5x watering in hot weather) are conservative engine estimates. The authoritative extension sources read (Clemson, UMN, RHS, Almanac) emphasize cold/frost hardiness and a fixed 1-2 in/week watering baseline but do not state an explicit upper heat-stress temperature or a quantitative hot-weather watering multiplier for peach; these values are inferred from the general stone-fruit watering guidance and should be revisited with a heat-specific extension source.","url":"https://extension.umn.edu/fruit/growing-stone-fruits-home-garden","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('pyrus-communis', 'Pyrus communis', array['Pear','European pear','Common pear']::text[], 'fruit', 'tree', false, false, 1, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":180,"fruitingIntervalDays":180,"preferredNpk":"10-10-10"}'::jsonb, '{"recommendedMinLiters":90,"idealMinLiters":90,"idealMaxLiters":125,"soilMixTags":["loam-based","well-drained","peat-free","John Innes No.3"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6}'::jsonb, '{"coldHardyMinC":-29,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"4":[{"startMonth":4,"endMonth":5}],"5":[{"startMonth":4,"endMonth":5}],"6":[{"startMonth":3,"endMonth":4}],"7":[{"startMonth":2,"endMonth":4}],"8":[{"startMonth":2,"endMonth":3}]},"productiveMonths":[8,9,10,11],"dormancyMonths":[12,1,2]}'::jsonb, array['Fire blight is the primary disease threat; avoid excess nitrogen, which increases susceptibility. Prune out diseased limbs at least 15 cm (6 in) below visible infection and disinfect pruners between cuts.','Other common problems: pear psylla, codling moth, wood-boring beetles, anthracnose, canker, scab, and powdery mildew.','Vole and rabbit bark damage on young trees; protect trunks.','Pears flower earlier than apples and are vulnerable to late-frost damage to blossoms; site in a sheltered spot protected from late frost.','Most varieties need a second compatible pear variety flowering at the same time for reliable fruit set; some cultivars are only partially self-fruitful.','This is a large tree (10-15 m / 25-50 ft in the ground). Container growing requires a dwarfing rootstock (e.g. Quince C / Quince Eline) and a large pot, roughly 45-50 cm wide and deep (about 90-125 L); the recommendedMinLiters value reflects that container minimum, not in-ground needs.']::text[], 0.2, '[{"citation":"University of Minnesota Extension — Growing pears in the home garden. Full sun; soil pH 6 to 7, well-drained; water newly planted trees weekly the first year, deep water established trees during dry seasons; fertilizer generally unnecessary, apply only if annual new growth is below 18 in, and excess nitrogen increases fire blight; two varieties generally needed for pollination; hardy varieties suit USDA zones 3-4; bare-root planting in early spring, potted after frost danger (May-June); harvest mid-August through late September; fire blight, Japanese beetles, vole/rabbit damage.","url":"https://extension.umn.edu/fruit/growing-pears","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing pears: feeding generally unnecessary; apply compost/fertilizer only if annual new growth falls below 18 in; excess nitrogen increases fire blight susceptibility.","url":"https://extension.umn.edu/fruit/growing-pears","field":"feedingProfile"},{"citation":"University of Minnesota Extension — Growing pears: bare-root trees planted in early spring when soil is workable; potted trees after frost danger passes (May-June); harvest mid-August through late September; two varieties needed for pollination; hardy varieties suit USDA zones 3-4.","url":"https://extension.umn.edu/fruit/growing-pears","field":"seasonality"},{"citation":"NC State Extension Gardener Plant Toolbox — Pyrus communis: ''Full sun (6 or more hours of direct sunlight a day)''; tolerates occasionally dry soil and prefers good drainage; USDA hardiness zones 4a-8b; deciduous tree 40-50 ft tall, 25-35 ft wide, erect spreading form; flowers in spring, fruits summer/fall; pests pear psylla, codling moth, wood-boring beetles; diseases fire blight, anthracnose, canker, scab, powdery mildew.","url":"https://plants.ces.ncsu.edu/plants/pyrus-communis/","field":"lightProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Pyrus communis: USDA hardiness zones 4a-8b. Zone 4a corresponds to roughly -34 to -32 C; coldHardyMinC set conservatively to -29 C to represent the species/zone-5 range rather than the coldest cultivars. Frost-sensitive blossoms per RHS (pears flower early and are at risk from late frost).","url":"https://plants.ces.ncsu.edu/plants/pyrus-communis/","field":"temperatureProfile"},{"citation":"NC State Extension Gardener Plant Toolbox — Pyrus communis: deciduous tree, erect spreading form, 40-50 ft tall; frequent disease and insect problems; high maintenance.","url":"https://plants.ces.ncsu.edu/plants/pyrus-communis/","field":"commonIssues"},{"citation":"UGA Extension (CAES) — Home Garden Pears: plant trees 20 ft apart; sunlight most or all day maximizes fruit; fertilize with 1 cup of 10-10-10 per tree per year of tree age (max 12 cups), half before growth begins and half after fruit set; Orient, Baldwin, Kieffer, Spalding are partially self-fruitful, otherwise plant compatible cross-pollinating varieties; fire blight management — remove diseased limbs 6 in below infection, disinfect pruners with rubbing alcohol or 1:9 bleach:water.","url":"https://fieldreport.caes.uga.edu/publications/C742/home-garden-pears/","field":"feedingProfile"},{"citation":"UGA Extension (CAES) — Home Garden Pears: fertilizer applied in two splits per year (half before growth, half after fruit set), supporting a ~180-day base feeding interval for in-ground trees; sunlight most or all of the day.","url":"https://fieldreport.caes.uga.edu/publications/C742/home-garden-pears/","field":"lightProfile"},{"citation":"RHS — How to grow pears: pears crop best in warm, sunny, sheltered position protected from late frosts; newly planted trees watered regularly during dry spells for the first couple of years; container trees need steady moisture through the growing season; ground trees need no regular feeding if mulched, container trees fed with an organic high-potassium liquid fertiliser every fortnight through the growing season; container pot size 45-50 cm (18-20 in) wide and deep on dwarfing rootstock (Quince C / Quince Eline) with loam-based peat-free compost (John Innes No.3); most varieties need another pear flowering at the same time; harvest September-November depending on variety.","url":"https://www.rhs.org.uk/fruit/pears/grow-your-own","field":"containerProfile"},{"citation":"RHS — How to grow pears: container trees benefit from feeding every fortnight (≈14 days) with high-potassium liquid fertiliser through the growing season, informing the containerLeachAdjustment; ground trees fed little if mulched.","url":"https://www.rhs.org.uk/fruit/pears/grow-your-own","field":"feedingProfile"},{"citation":"RHS — How to grow pears: pears flower earlier than apples and are at greater risk of late-frost damage to blossom; site in a sheltered position protected from late frosts. Supports frostSensitive=true and the late-frost commonIssue.","url":"https://www.rhs.org.uk/fruit/pears/grow-your-own","field":"temperatureProfile"},{"citation":"Confidence note: heatStressC (35 C) is an estimate. None of the authoritative sources read (UMN, NC State, UGA, RHS) state an explicit upper heat-stress temperature for Pyrus communis; 35 C is a conservative placeholder consistent with the species'' temperate zone-4a-8b range. hotWeatherMultiplier (1.5) and rainSkipThresholdMm (12) are reasonable care-engine defaults extrapolated from ''deep water during dry seasons / very dry spells when fruit is swelling'' guidance rather than explicit published figures.","url":"https://plants.ces.ncsu.edu/plants/pyrus-communis/","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('vitis-vinifera', 'Vitis vinifera', array['Grape','European grape','Wine grape','Common grape vine']::text[], 'vine', 'climbing', true, true, 0, '{"baseIntervalDays":7,"dryingTolerance":"high","overwaterRisk":"high","hotWeatherMultiplier":0.5,"rainSkipThresholdMm":13}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"postHarvestIntervalDays":30,"containerLeachAdjustment":0.75,"preferredNpk":"high-potassium (e.g. tomato feed)"}'::jsonb, '{"recommendedMinLiters":21,"idealMinLiters":30,"idealMaxLiters":45,"soilMixTags":["loam-based","John Innes No3","free-draining","well-drained"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-23,"heatStressC":38,"frostSensitive":true}'::jsonb, '{"productiveMonths":[8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['European (Vitis vinifera) grapes are the least cold-hardy grape type; midwinter dormant bud injury occurs roughly between -22 C and -26 C, so they suit warmer zones (about USDA 6-9) or need winter protection in colder regions.','Requires a sturdy trellis, wires, fence or arbor; without support the vine trails along the ground.','Young spring shoots after bud break are very susceptible to late-frost injury, which reduces yield.','Roots dislike sitting in wet or poorly drained soil; plant in well-drained ground and avoid overwatering.','Best grown in the ground; the listed container minimum (about 21 L / a 30 cm wide-and-deep pot per RHS) supports a single trained vine but full long-term vigor and yield favor in-ground planting.','Needs annual dormant-season pruning (before leaves emerge) to control vigor and fruit well.','Stop feeding once grapes begin to ripen and colour up, as extra feeding then can spoil flavour.']::text[], 0.95, '[{"citation":"UMN Extension - Growing grapes in the home garden (full sun; young vines need about 1/2 to 1 inch of water per week for the first two years; ~6 ft spacing per vine; self-pollinating, wind/insect pollinated; annual spring pruning; trellis/support required; spring compost feeding).","url":"https://extension.umn.edu/fruit/growing-grapes-home-garden","field":"wateringProfile"},{"citation":"UMN Extension - Growing grapes in the home garden (vines are self-pollinating; flowers pollinated by wind and insects).","url":"https://extension.umn.edu/fruit/growing-grapes-home-garden","field":"selfFruitful"},{"citation":"OSU Extension EC 1639 - Growing table grapes (full sunlight required for good table-grape production; European cultivars planted 6 ft apart in rows; trellis with training wires required; grow best in well-drained soils; young spring shoots very susceptible to frost injury after bud break).","url":"https://extension.oregonstate.edu/catalog/ec-1639-growing-table-grapes","field":"lightProfile"},{"citation":"OSU Extension EC 1639 - Growing table grapes (grapevines grow best in well-drained soils; roots do not tolerate waterlogged conditions).","url":"https://extension.oregonstate.edu/catalog/ec-1639-growing-table-grapes","field":"wateringProfile"},{"citation":"OSU Extension EC 1639 - Growing table grapes (trellis required; young spring shoots very susceptible to frost injury after April/May bud break).","url":"https://extension.oregonstate.edu/catalog/ec-1639-growing-table-grapes","field":"temperatureProfile"},{"citation":"RHS - How to grow grapes / Grapes: outdoor cultivation (containers: pot about 30-38 cm (12-15 in) in diameter and depth, loam-based John Innes No3 compost; warm sheltered sunny site; almost all grape varieties self-fertile, mostly wind-pollinated; feed dessert grapes every 2-3 weeks with a high-potassium liquid feed such as tomato feed from a month after spring growth until grapes ripen, then stop; fairly drought tolerant; trained along horizontal wires).","url":"https://www.rhs.org.uk/fruit/grapes/outdoor-cultivation","field":"containerProfile"},{"citation":"RHS - Grapes: outdoor cultivation (feed every 2-3 weeks with a high-potassium feed such as tomato feed from ~1 month after spring growth starts until grapes ripen; stop feeding once grapes colour up).","url":"https://www.rhs.org.uk/fruit/grapes/outdoor-cultivation","field":"feedingProfile"},{"citation":"RHS - How to grow grapes (vines are fairly drought tolerant; container vines need regular watering during the growing season; established in-ground vines often need no supplemental water).","url":"https://www.rhs.org.uk/fruit/grapes/grow-your-own","field":"wateringProfile"},{"citation":"Old Farmer''s Almanac - Grapes (full sun; young grapes require about 1/2 to 1 inch of water per week; each vine needs about 6 ft of space; vines need a trellis/arbor support; European grapes do well in warm, dry Mediterranean-type zones).","url":"https://www.almanac.com/plant/grapes","field":"lightProfile"},{"citation":"OSU/Cornell-cited grapevine cold-hardiness data: maximum midwinter cold hardiness of common Vitis vinifera buds ranges roughly -14.3 F to -7.4 F (about -25.7 C to -21.9 C); V. vinifera is the least cold-hardy grape type. coldHardyMinC set conservatively to -23 C; suited to roughly USDA zones 6-9.","url":"https://extension.oregonstate.edu/catalog/em-9432-grapevine-training-systems-managing-winter-cold-injury","field":"temperatureProfile"},{"citation":"Confidence note: heatStressC (38 C), hotWeatherMultiplier, rainSkipThresholdMm, container liter conversions, and exact dormancy/productive months are estimated. Sources give qualitative guidance (full sun, drought tolerant once established, Mediterranean-adapted, pot 30-38 cm, 1/2-1 inch/week young vines) but not exact daily watering intervals, heat-stress thresholds, or month windows; these were converted/estimated conservatively from the cited care text. Productive/dormancy months are Northern-Hemisphere temperate-climate generalizations and shift by region and cultivar.","field":"confidence"}]'::jsonb, 1, '2026-06-02')
